import{_ as e,e as d}from"./app.9a3bc5e3.js";const o={},c=d('<p>\u7B80\u8981\u4ECB\u7ECD\u5E38\u89C1\u4E2D\u95F4\u4EF6</p><h2 id="redis" tabindex="-1"><a class="header-anchor" href="#redis" aria-hidden="true">#</a> Redis</h2><h2 id="zookeeper" tabindex="-1"><a class="header-anchor" href="#zookeeper" aria-hidden="true">#</a> Zookeeper</h2><p><code>zookeeper</code> \u662F\u4E00\u4E2A\u5206\u5E03\u5F0F\u670D\u52A1\u6846\u67B6\uFF0C\u662F <code>Apache Hadoop</code> \u7684\u4E00\u4E2A\u5B50\u9879\u76EE\uFF0C\u5B83\u4E3B\u8981\u662F\u7528\u6765\u89E3\u51B3\u5206\u5E03\u5F0F\u5E94\u7528\u4E2D\u7ECF\u5E38\u9047\u5230\u7684\u4E00\u4E9B\u6570\u636E\u7BA1\u7406\u95EE\u9898\uFF0C\u5982\uFF1A\u7EDF\u4E00\u547D\u540D\u670D\u52A1\u3001\u72B6\u6001\u540C\u6B65\u670D\u52A1\u3001\u96C6\u7FA4\u7BA1\u7406\u3001\u5206\u5E03\u5F0F\u5E94\u7528\u914D\u7F6E\u9879\u7684\u7BA1\u7406\u7B49\u3002</p><ul><li><p>\u7ED3\u70B9\u7C7B\u578B\uFF1A</p><ul><li><p>\u4E34\u65F6\u8282\u70B9\uFF1A\u4E34\u65F6\u8282\u70B9\u7684\u751F\u547D\u5468\u671F\u548C\u5BA2\u6237\u7AEF\u4F1A\u8BDD\u7ED1\u5B9A\u5728\u4E00\u8D77\uFF0C\u5BA2\u6237\u7AEF\u4F1A\u8BDD\u5931\u6548\uFF0C\u5219\u8FD9\u4E2A\u8282\u70B9\u5C31\u4F1A\u88AB\u81EA\u52A8\u6E05\u9664\u3002</p></li><li><p>\u6C38\u4E45\u8282\u70B9\uFF1A\u8BE5\u6570\u636E\u8282\u70B9\u88AB\u521B\u5EFA\u540E\uFF0C\u5C31\u4F1A\u4E00\u76F4\u5B58\u5728\u4E8E <code>zookeeper</code> \u670D\u52A1\u5668\u4E0A\uFF0C\u76F4\u5230\u6709\u5220\u9664\u64CD\u4F5C\u6765\u4E3B\u52A8\u5220\u9664\u8FD9\u4E2A\u8282\u70B9\u3002</p></li></ul></li></ul><h3 id="\u4F7F\u7528\u573A\u666F" tabindex="-1"><a class="header-anchor" href="#\u4F7F\u7528\u573A\u666F" aria-hidden="true">#</a> \u4F7F\u7528\u573A\u666F</h3><p>\u914D\u7F6E\u4E2D\u5FC3\uFF1A\u914D\u7F6E\u4E2D\u5FC3\uFF0C\u987E\u540D\u601D\u4E49\u5C31\u662F\u5C06\u914D\u7F6E\u6570\u636E\u5199\u5230 <code>ZK</code> \u8282\u70B9\u4E0A\uFF0C\u4F9B\u5404\u4E2A\u5206\u5E03\u5F0F\u673A\u5668\u83B7\u53D6\u914D\u7F6E\uFF0C\u540C\u65F6\u76D1\u542C\u81EA\u5DF1\u5BF9\u5E94\u7684\u8282\u70B9\u3002\u5B9E\u73B0\u914D\u7F6E\u4FE1\u606F\u7684\u96C6\u4E2D\u5F0F\u7BA1\u7406\u548C\u52A8\u6001\u66F4\u65B0\u3002</p><p>\u547D\u540D\u670D\u52A1\uFF1A\u5728\u5206\u5E03\u5F0F\u7CFB\u7EDF\u4E2D\uFF0C\u901A\u8FC7\u4F7F\u7528\u547D\u540D\u670D\u52A1\uFF0C\u5BA2\u6237\u7AEF\u5E94\u7528\u80FD\u591F\u6839\u636E\u6307\u5B9A\u540D\u5B57\u6765\u83B7\u53D6\u8D44\u6E90\u6216\u670D\u52A1\u7684\u5730\u5740\uFF0C\u63D0\u4F9B\u8005\u7B49\u4FE1\u606F\u3002\u88AB\u547D\u540D\u7684\u5B9E\u4F53\u901A\u5E38\u53EF\u4EE5\u662F\u96C6\u7FA4\u4E2D\u7684\u673A\u5668\uFF0C\u63D0\u4F9B\u7684\u670D\u52A1\u5730\u5740\uFF0C\u8FDC\u7A0B\u5BF9\u8C61\u7B49\u7B49\uFF0C\u8FD9\u4E9B\u6211\u4EEC\u90FD\u53EF\u4EE5\u7EDF\u79F0\u4ED6\u4EEC\u4E3A\u540D\u5B57(<code>Name</code>)\u3002\u901A\u8FC7\u8C03\u7528 <code>ZK</code> \u63D0\u4F9B\u7684\u521B\u5EFA\u8282\u70B9\u7684 <code>API</code>\uFF0C\u80FD\u591F\u5F88\u5BB9\u6613\u521B\u5EFA\u4E00\u4E2A\u5168\u5C40\u552F\u4E00\u7684 <code>path</code>\uFF0C\u8FD9\u4E2A <code>path</code> \u5C31\u53EF\u4EE5\u4F5C\u4E3A\u4E00\u4E2A\u540D\u79F0\u3002</p><p>\u5206\u5E03\u5F0F\u901A\u77E5\uFF1A<code>ZooKeeper</code> \u7684 <code>watcher</code> \u6CE8\u518C\u4E0E\u5F02\u6B65\u901A\u77E5\u673A\u5236\uFF0C\u80FD\u591F\u5F88\u597D\u7684\u5B9E\u73B0\u5206\u5E03\u5F0F\u73AF\u5883\u4E0B\u4E0D\u540C\u7CFB\u7EDF\u4E4B\u95F4\u7684\u901A\u77E5\u4E0E\u534F\u8C03\uFF0C\u5B9E\u73B0\u5BF9\u6570\u636E\u53D8\u66F4\u7684\u5B9E\u65F6\u5904\u7406\u3002\u4E0D\u540C\u7CFB\u7EDF\u90FD\u5BF9 <code>ZK</code> \u4E0A\u540C\u4E00\u4E2A <code>znode</code> \u8FDB\u884C\u6CE8\u518C\uFF0C\u76D1\u542C <code>znode</code> \u7684\u53D8\u5316\uFF08\u5305\u62EC <code>znode</code> \u672C\u8EAB\u5185\u5BB9\u53CA\u5B50\u8282\u70B9\u7684)\uFF0C\u5176\u4E2D\u4E00\u4E2A\u7CFB\u7EDF <code>update</code> \u4E86 <code>znode</code>\uFF0C\u90A3\u4E48\u53E6\u4E00\u4E2A\u7CFB\u7EDF\u80FD\u591F\u6536\u5230\u901A\u77E5\uFF0C\u5E76\u4F5C\u51FA\u76F8\u5E94\u5904\u7406</p><p>\u9009\u4E3B\uFF1A\u5229\u7528 <code>ZooKeeper</code> \u7684\u4E00\u81F4\u6027\uFF0C\u80FD\u591F\u4FDD\u8BC1\u5728\u5206\u5E03\u5F0F\u9AD8\u5E76\u53D1\u60C5\u51B5\u4E0B\u8282\u70B9\u521B\u5EFA\u7684\u5168\u5C40\u552F\u4E00\u6027\uFF0C\u5373\uFF1A\u540C\u65F6\u6709\u591A\u4E2A\u5BA2\u6237\u7AEF\u8BF7\u6C42\u521B\u5EFA <code>/currentMaster</code> \u8282\u70B9\uFF0C\u6700\u7EC8\u4E00\u5B9A\u53EA\u6709\u4E00\u4E2A\u5BA2\u6237\u7AEF\u8BF7\u6C42\u80FD\u591F\u521B\u5EFA\u6210\u529F\u3002\u5229\u7528\u8FD9\u4E2A\u7279\u6027\uFF0C\u5C31\u80FD\u5F88\u8F7B\u6613\u7684\u5728\u5206\u5E03\u5F0F\u73AF\u5883\u4E2D\u8FDB\u884C\u96C6\u7FA4\u9009\u53D6\u4E86\u3002</p><p>\u5206\u5E03\u5F0F\u9501\uFF1A\u5206\u5E03\u5F0F\u9501\uFF0C\u8FD9\u4E2A\u4E3B\u8981\u5F97\u76CA\u4E8E <code>ZooKeeper</code> \u7684\u8282\u70B9\u521B\u5EFA\u548C\u4E8B\u4EF6\u76D1\u542C\u673A\u5236\u3002</p><h2 id="rabbit-mq" tabindex="-1"><a class="header-anchor" href="#rabbit-mq" aria-hidden="true">#</a> Rabbit MQ</h2><p><code>Rabbit MQ</code> \u662F\u4E00\u4E2A\u7531 <code>erlang</code> \u5F00\u53D1\u7684 <code>AMQP\uFF08Advanced Message Queue\uFF09</code> \u7684\u5F00\u6E90\u5B9E\u73B0</p><h3 id="\u6A21\u5757\u4ECB\u7ECD" tabindex="-1"><a class="header-anchor" href="#\u6A21\u5757\u4ECB\u7ECD" aria-hidden="true">#</a> \u6A21\u5757\u4ECB\u7ECD</h3><p><code>Broker</code>\uFF1A\u53EF\u4EE5\u7B80\u5355\u7406\u89E3\u4E3A\u4E00\u53F0\u7269\u7406\u673A\u5668\u3002</p><p><code>Producer</code>\uFF1A\u6D88\u606F\u751F\u4EA7\u8005\uFF0C\u5C31\u662F\u6295\u9012\u6D88\u606F\u7684\u7A0B\u5E8F\u3002</p><p><code>Consumer</code>\uFF1A\u6D88\u606F\u6D88\u8D39\u8005\uFF0C\u5C31\u662F\u63A5\u53D7\u6D88\u606F\u7684\u7A0B\u5E8F\u3002</p><p><code>Exchange</code>\uFF1A\u6D88\u606F\u4EA4\u6362\u673A\uFF0C\u5B83\u6307\u5B9A\u6D88\u606F\u6309\u4EC0\u4E48\u89C4\u5219\uFF0C\u8DEF\u7531\u5230\u54EA\u4E2A\u961F\u5217\u3002 <code>fanout|direct|topic|headerQueue</code>\uFF1A\u6D88\u606F\u7684\u8F7D\u4F53\uFF0C\u6BCF\u4E2A\u6D88\u606F\u90FD\u4F1A\u88AB\u6295\u5230\u4E00\u4E2A\u6216\u591A\u4E2A\u961F\u5217\u3002</p><p><code>Binding</code>\uFF1A\u7ED1\u5B9A\uFF0C\u5B83\u7684\u4F5C\u7528\u5C31\u662F\u628A <code>exchange</code> \u548C <code>queue</code> \u6309\u7167\u8DEF\u7531\u89C4\u5219\u7ED1\u5B9A\u8D77\u6765\u3002</p><p><code>Routing Key</code>\uFF1A\u8DEF\u7531\u5173\u952E\u5B57\uFF0C<code>exchange</code> \u6839\u636E\u8FD9\u4E2A\u5173\u952E\u5B57\u8FDB\u884C\u6D88\u606F\u6295\u9012\u3002</p><p><code>vhost</code>\uFF1A\u865A\u62DF\u4E3B\u673A\uFF0C\u4E00\u4E2A <code>broker</code> \u91CC\u53EF\u4EE5\u6709\u591A\u4E2A <code>vhost</code>\uFF0C\u7528\u4F5C\u4E0D\u540C\u7528\u6237\u7684\u6743\u9650\u5206\u79BB\u3002</p><h3 id="\u5E94\u7528" tabindex="-1"><a class="header-anchor" href="#\u5E94\u7528" aria-hidden="true">#</a> \u5E94\u7528</h3><p>\u6D88\u606F\u4F20\u9012\u3001\u5F02\u6B65\u5904\u7406\u3001\u5E94\u7528\u89E3\u8026\u3001\u6D41\u91CF\u524A\u5CF0</p><h3 id="\u9AD8\u53EF\u7528" tabindex="-1"><a class="header-anchor" href="#\u9AD8\u53EF\u7528" aria-hidden="true">#</a> \u9AD8\u53EF\u7528</h3><p>\u53D1\u9001\u65B9\uFF1A<code>confirm</code> \u673A\u5236\uFF08\u53D1\u9001\u6210\u529F\u540E\u6709\u5F02\u6B65\u901A\u77E5\uFF09</p><p>\u6D88\u8D39\u7AEF\uFF1A<code>ACK</code> \u6D88\u606F\u5E94\u7B54\u673A\u5236</p><p><code>rabbit</code>\uFF1A<code>queue</code> \u6301\u4E45\u5316\uFF0C\u6D88\u606F\u6301\u4E45\u5316\uFF08<code>deliveryMode = 2</code>\uFF09</p><h2 id="nginx" tabindex="-1"><a class="header-anchor" href="#nginx" aria-hidden="true">#</a> Nginx</h2><p><code>Nginx</code> \u662F\u4E00\u6B3E\u8F7B\u91CF\u7EA7\u7684 <code>Web</code> \u670D\u52A1\u5668/\u53CD\u5411\u4EE3\u7406\u670D\u52A1\u5668\u53CA\u7535\u5B50\u90AE\u4EF6<code>\uFF08IMAP/POP3)</code>\u4EE3\u7406\u670D\u52A1\u5668\uFF0C\u5728 <code>BSD-like</code> \u534F\u8BAE\u4E0B\u53D1\u884C\u3002\u5176\u7279\u70B9\u662F\u5360\u6709\u5185\u5B58\u5C11\uFF0C\u5E76\u53D1\u80FD\u529B\u5F3A\uFF0C\u4E8B\u5B9E\u4E0A <code>nginx</code> \u7684\u5E76\u53D1\u80FD\u529B\u5728\u540C\u7C7B\u578B\u7684\u7F51\u9875\u670D\u52A1\u5668\u4E2D\u51E0\u4E4E\u6210\u4E3A\u516C\u8BA4\u7684\u6807\u6746\uFF0C\u5728\u767E\u5EA6\u3001\u4EAC\u4E1C\u3001\u65B0\u6D6A\u3001\u7F51\u6613\u3001\u817E\u8BAF\u3001\u6DD8\u5B9D\u7B49\u4E92\u8054\u7F51\u516C\u53F8\u4E2D\u5747\u6709\u5E94\u7528\u3002</p><h3 id="\u52A8\u9759\u5206\u79BB" tabindex="-1"><a class="header-anchor" href="#\u52A8\u9759\u5206\u79BB" aria-hidden="true">#</a> \u52A8\u9759\u5206\u79BB</h3><p>\u9759\u6001\u8D44\u6E90\uFF1A\u7531 <code>nginx</code> \u4F5C\u4E3A <code>web</code> \u670D\u52A1\u5668\u8EAB\u4EFD\uFF0C\u76F4\u63A5\u8FD4\u56DE</p><p>\u52A8\u6001\u8D44\u6E90\uFF1A<code>nginx</code> \u5C06\u8BF7\u6C42\u8F6C\u53D1\u51FA\u53BB\uFF0C\u4EA4\u7ED9\u540E\u7AEF\u5E94\u7528\u670D\u52A1\u5668\u5904\u7406</p><h3 id="\u8D1F\u8F7D\u5747\u8861" tabindex="-1"><a class="header-anchor" href="#\u8D1F\u8F7D\u5747\u8861" aria-hidden="true">#</a> \u8D1F\u8F7D\u5747\u8861</h3><p>\u5F53\u7F51\u7AD9\u7684\u8BBF\u95EE\u91CF\u8FBE\u5230\u4E00\u5B9A\u7A0B\u5EA6\u540E\uFF0C\u5355\u53F0\u670D\u52A1\u5668\u4E0D\u80FD\u6EE1\u8DB3\u7528\u6237\u7684\u8BF7\u6C42\u65F6\uFF0C\u9700\u8981\u7528\u591A\u53F0\u670D\u52A1\u5668\u96C6\u7FA4\u63D0\u5347\u5E76\u884C\u5904\u7406\u80FD\u529B\u3002\u5E76\u4E14\u591A\u53F0\u670D\u52A1\u5668\u53EF\u4EE5\u5E73\u5747\u5206\u62C5\u8D1F\u8F7D\uFF0C\u4E0D\u4F1A\u56E0\u4E3A\u67D0\u53F0\u670D\u52A1\u5668\u8D1F\u8F7D\u9AD8\u5B95\u673A\u800C\u67D0\u53F0\u670D\u52A1\u5668\u95F2\u7F6E\u7684\u60C5\u51B5\u3002\u8FD9\u65F6\u4F7F\u7528 <code>nginx</code> \u5B9E\u73B0\u4E86\u673A\u5668\u4E4B\u95F4\u7684\u8D1F\u8F7D\u5747\u8861\u3002</p>',34);function a(r,i){return c}var p=e(o,[["render",a]]);export{p as default};
